-- Справочники заказчика: поставщики (suppliers) и контрагенты
-- (customer_counterparties). ОТДЕЛЬНЫЕ таблицы, НЕ операционная
-- counterparties — на FK приёмок/отгрузок и sync мобилы не влияют.
-- inn — text без строгих констрейнтов (в источнике встречаются «грязные»
-- ИНН: запятые, 11 знаков, префикс «ИНН …»); правится вручную в Справочниках.
-- id и created_at сохраняются из источника заказчика (идемпотентный re-seed).
CREATE TABLE IF NOT EXISTS "suppliers" (
  "id" uuid PRIMARY KEY DEFAULT gen_random_uuid() NOT NULL,
  "inn" text DEFAULT '' NOT NULL,
  "name" text NOT NULL,
  "aliases" text[] DEFAULT '{}'::text[] NOT NULL,
  "last_security_status" varchar(32),
  "founding_documents_comment" text,
  "created_at" timestamp with time zone DEFAULT now() NOT NULL,
  "updated_at" timestamp with time zone DEFAULT now() NOT NULL
);
--> statement-breakpoint
CREATE INDEX IF NOT EXISTS "supplier_name_idx" ON "suppliers" USING btree ("name");
--> statement-breakpoint
CREATE TABLE IF NOT EXISTS "customer_counterparties" (
  "id" uuid PRIMARY KEY DEFAULT gen_random_uuid() NOT NULL,
  "inn" text DEFAULT '' NOT NULL,
  "name" text NOT NULL,
  "aliases" text[] DEFAULT '{}'::text[] NOT NULL,
  "address" text,
  "created_at" timestamp with time zone DEFAULT now() NOT NULL,
  "updated_at" timestamp with time zone DEFAULT now() NOT NULL
);
--> statement-breakpoint
CREATE INDEX IF NOT EXISTS "customer_counterparty_name_idx" ON "customer_counterparties" USING btree ("name");
--> statement-breakpoint
